import { useState, useEffect, useCallback, useRef } from "react";

// ── WAKE LOCK ─────────────────────────────────────────────────────────────
function useWakeLock() {
  const ref = useRef(null);
  const [active, setActive] = useState(false);
  const request = useCallback(async () => {
    if (!("wakeLock" in navigator)) return;
    try {
      ref.current = await navigator.wakeLock.request("screen");
      setActive(true);
      ref.current.addEventListener("release", () => setActive(false));
    } catch {}
  }, []);
  const release = useCallback(() => {
    if (ref.current) { ref.current.release(); ref.current = null; setActive(false); }
  }, []);
  useEffect(() => {
    const reacquire = () => { if (active) request(); };
    document.addEventListener("visibilitychange", reacquire);
    return () => document.removeEventListener("visibilitychange", reacquire);
  }, [active, request]);
  return { active, request, release };
}

