// ── STORAGE ───────────────────────────────────────────────────────────────
const STORAGE_KEY = "nunofit_v4";
function loadData() {
  try { const r = localStorage.getItem(STORAGE_KEY); return r ? JSON.parse(r) : { sessions: [], weights: [], nutrition: [] }; }
  catch { return { sessions: [], weights: [], nutrition: [] }; }
}
function saveData(d) { try { localStorage.setItem(STORAGE_KEY, JSON.stringify(d)); } catch {} }
function formatDuration(m) {
  if (!m) return "—";
  const h = Math.floor(m / 60), min = m % 60;
  return h > 0 ? `${h}h ${min}min` : `${min}min`;
}
function today() { return new Date().toISOString().split("T")[0]; }
function monthKey(d) { return d?.slice(0, 7); }
function getMonthName(ym) {
  if (!ym) return "";
  const [y, m] = ym.split("-");
  return new Date(+y, +m - 1).toLocaleDateString("pt-PT", { month: "long", year: "numeric" });
}

