// ── NUTRITION TAB ─────────────────────────────────────────────────────────
function NutritionTab({ nutrition, onSave, onDelete }) {
  const [selectedDate, setSelectedDate] = useState(today());
  const [editMeal, setEditMeal] = useState(null); // { mealId, overrides: {itemIndex: kcal} }
  const [showLog, setShowLog] = useState(false);

  const dayLog = nutrition.filter(n => n.date === selectedDate);
  const loggedMealIds = new Set(dayLog.map(n => n.mealId));

  const getMealKcal = (meal, overrides = {}) =>
    meal.items.reduce((s, item, i) => s + (overrides[i] !== undefined ? +overrides[i] : item.kcal), 0);

  const totalLogged = dayLog.reduce((s, n) => s + n.totalKcal, 0);

  const inp = { padding: "8px 10px", background: "#0d0d1a", border: "1px solid #ffffff15",
    borderRadius: 8, color: "#f0f0f0", fontSize: 14, boxSizing: "border-box", outline: "none" };

  return (
    <div>
      {/* Date selector */}
      <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 16 }}>
        <input type="date" value={selectedDate} onChange={e => setSelectedDate(e.target.value)}
          style={{ ...inp, flex: 1 }} />
      </div>

      {/* Daily total */}
      <div style={{ background: "linear-gradient(135deg, #f77f0022, #0d0d1a)",
        border: "1px solid #f77f0033", borderRadius: 14, padding: "14px 16px", marginBottom: 16 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
          <div>
            <div style={{ color: "#888", fontSize: 11, fontWeight: 600, textTransform: "uppercase" }}>Total do dia</div>
            <div style={{ color: "#f77f00", fontWeight: 900, fontSize: 28 }}>{totalLogged} <span style={{ fontSize: 14, fontWeight: 400 }}>kcal</span></div>
          </div>
          <div style={{ textAlign: "right" }}>
            <div style={{ color: "#888", fontSize: 11, fontWeight: 600, textTransform: "uppercase" }}>Plano</div>
            <div style={{ color: "#555", fontWeight: 700, fontSize: 18 }}>{TOTAL_KCAL} kcal</div>
          </div>
        </div>
        {totalLogged > 0 && (
          <div style={{ marginTop: 10 }}>
            <div style={{ height: 6, background: "#ffffff0a", borderRadius: 3, overflow: "hidden" }}>
              <div style={{ height: "100%", borderRadius: 3,
                width: `${Math.min(100, (totalLogged / TOTAL_KCAL) * 100)}%`,
                background: totalLogged > TOTAL_KCAL ? "#e85d04" : "#2d6a4f",
                transition: "width 0.3s" }} />
            </div>
            <div style={{ color: "#555", fontSize: 11, marginTop: 4 }}>
              {totalLogged > TOTAL_KCAL
                ? `+${totalLogged - TOTAL_KCAL} kcal acima do plano`
                : `${TOTAL_KCAL - totalLogged} kcal em falta`}
            </div>
          </div>
        )}
      </div>

      {/* Meals */}
      {MEAL_PLAN.map(meal => {
        const logged = dayLog.find(n => n.mealId === meal.id);
        const isLogged = !!logged;
        const mealKcal = isLogged ? logged.totalKcal : getMealKcal(meal);

        return (
          <div key={meal.id} style={{ background: "#1a1a2e",
            border: `1px solid ${isLogged ? meal.color + "44" : "#ffffff0a"}`,
            borderLeft: `3px solid ${meal.color}`,
            borderRadius: 12, marginBottom: 10, overflow: "hidden" }}>
            {/* Meal header */}
            <div style={{ display: "flex", alignItems: "center", gap: 10, padding: "12px 14px" }}>
              <span style={{ fontSize: 22 }}>{meal.icon}</span>
              <div style={{ flex: 1 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                  <span style={{ fontWeight: 700, color: "#f0f0f0", fontSize: 14 }}>{meal.nome}</span>
                  {isLogged && <span style={{ fontSize: 10, color: "#2d6a4f", fontWeight: 700 }}>✓</span>}
                </div>
                <div style={{ color: "#666", fontSize: 12 }}>{meal.hora} · <span style={{ color: meal.color, fontWeight: 700 }}>{mealKcal} kcal</span></div>
              </div>
              {!isLogged ? (
                <button onClick={() => setEditMeal({ mealId: meal.id, overrides: {} })}
                  style={{ background: meal.color + "22", border: `1px solid ${meal.color}44`,
                    color: meal.color, borderRadius: 8, padding: "6px 10px",
                    fontSize: 12, fontWeight: 700, cursor: "pointer" }}>
                  + Registar
                </button>
              ) : (
                <button onClick={() => onDelete(logged.id)}
                  style={{ background: "none", border: "none", color: "#444", cursor: "pointer", fontSize: 18 }}>×</button>
              )}
            </div>

            {/* Items list (collapsed if logged) */}
            {!isLogged && (
              <div style={{ borderTop: "1px solid #ffffff08", padding: "0 14px 10px" }}>
                {meal.items.map((item, i) => (
                  <div key={i} style={{ display: "flex", justifyContent: "space-between",
                    padding: "5px 0", borderBottom: i < meal.items.length - 1 ? "1px solid #ffffff05" : "none" }}>
                    <span style={{ color: "#aaa", fontSize: 13 }}>{item.nome} <span style={{ color: "#555" }}>({item.qty})</span></span>
                    <span style={{ color: "#666", fontSize: 13 }}>{item.kcal} kcal</span>
                  </div>
                ))}
                {meal.suplementos && (
                  <div style={{ marginTop: 8, color: "#555", fontSize: 11 }}>
                    💊 {meal.suplementos.join(" · ")}
                  </div>
                )}
                {meal.nota && <div style={{ marginTop: 6, color: "#555", fontSize: 11, fontStyle: "italic" }}>{meal.nota}</div>}
              </div>
            )}
          </div>
        );
      })}

      {/* Edit/Log Modal */}
      {editMeal && (() => {
        const meal = MEAL_PLAN.find(m => m.id === editMeal.mealId);
        const totalKcal = getMealKcal(meal, editMeal.overrides);
        return (
          <div style={{ position: "fixed", inset: 0, background: "#000000cc",
            display: "flex", alignItems: "flex-end", justifyContent: "center", zIndex: 100 }}>
            <div style={{ background: "#13131f", border: "1px solid #ffffff10",
              borderRadius: "20px 20px 0 0", padding: "24px 20px",
              width: "100%", maxWidth: 480, maxHeight: "85vh", overflowY: "auto" }}>
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
                <div>
                  <div style={{ fontWeight: 800, color: "#f0f0f0", fontSize: 17 }}>{meal.icon} {meal.nome}</div>
                  <div style={{ color: meal.color, fontWeight: 700, fontSize: 20, marginTop: 2 }}>{totalKcal} kcal</div>
                </div>
                <button onClick={() => setEditMeal(null)}
                  style={{ background: "#ffffff0a", border: "none", color: "#888",
                    width: 32, height: 32, borderRadius: 8, cursor: "pointer", fontSize: 14 }}>✕</button>
              </div>
              <div style={{ color: "#666", fontSize: 12, marginBottom: 12 }}>Ajusta as calorias se comeres quantidades diferentes:</div>
              {meal.items.map((item, i) => (
                <div key={i} style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 10 }}>
                  <div style={{ flex: 1 }}>
                    <div style={{ color: "#d0d0d0", fontSize: 13 }}>{item.nome}</div>
                    <div style={{ color: "#555", fontSize: 11 }}>{item.qty}</div>
                  </div>
                  <input type="number" inputMode="numeric"
                    value={editMeal.overrides[i] !== undefined ? editMeal.overrides[i] : item.kcal}
                    onChange={e => setEditMeal(prev => ({ ...prev, overrides: { ...prev.overrides, [i]: e.target.value } }))}
                    style={{ ...inp, width: 72, textAlign: "center" }} />
                  <span style={{ color: "#555", fontSize: 12 }}>kcal</span>
                </div>
              ))}
              {meal.suplementos && (
                <div style={{ background: "#ffffff05", borderRadius: 8, padding: "8px 12px", marginBottom: 12 }}>
                  <div style={{ color: "#666", fontSize: 11, marginBottom: 4 }}>💊 Suplementos</div>
                  <div style={{ color: "#555", fontSize: 12 }}>{meal.suplementos.join(", ")}</div>
                </div>
              )}
              <button onClick={() => {
                onSave({ id: Date.now(), date: selectedDate, mealId: meal.id, totalKcal, overrides: editMeal.overrides });
                setEditMeal(null);
              }} style={{ width: "100%", padding: 14, background: meal.color, color: "#fff",
                border: "none", borderRadius: 10, fontWeight: 800, fontSize: 15, cursor: "pointer" }}>
                Guardar {totalKcal} kcal
              </button>
            </div>
          </div>
        );
      })()}
    </div>
  );
}

// ── LOG MODAL ─────────────────────────────────────────────────────────────
function LogModal({ workoutId, onSave, onClose }) {
  const workout = WORKOUTS[workoutId];
  const [duration, setDuration] = useState("");
  const [calories, setCalories] = useState("");
  const [notes, setNotes] = useState("");
  const [date, setDate] = useState(today());
  const inp = { width: "100%", padding: "10px 12px", background: "#0d0d1a", border: "1px solid #ffffff12",
    borderRadius: 8, color: "#f0f0f0", fontSize: 15, boxSizing: "border-box", outline: "none" };
  const lbl = { display: "block", color: "#666", fontSize: 12, fontWeight: 600,
    marginBottom: 6, marginTop: 14, textTransform: "uppercase", letterSpacing: 0.5 };
  return (
    <div style={{ position: "fixed", inset: 0, background: "#000000bb",
      display: "flex", alignItems: "flex-end", justifyContent: "center", zIndex: 100 }}>
      <div style={{ background: "#13131f", border: "1px solid #ffffff10",
        borderRadius: "20px 20px 0 0", padding: "24px 20px", width: "100%", maxWidth: 480, maxHeight: "90vh", overflowY: "auto" }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <div>
            <div style={{ fontWeight: 800, color: "#f0f0f0", fontSize: 17 }}>Registar {workout.label}</div>
            <div style={{ color: "#888", fontSize: 12 }}>{workout.focus}</div>
          </div>
          <button onClick={onClose} style={{ background: "#ffffff0a", border: "none", color: "#888",
            width: 32, height: 32, borderRadius: 8, cursor: "pointer", fontSize: 14, fontWeight: 700 }}>✕</button>
        </div>
        <label style={lbl}>Data</label>
        <input type="date" value={date} onChange={e => setDate(e.target.value)} style={inp} />
        <label style={lbl}>Duração (minutos)</label>
        <input type="number" placeholder="Ex: 55" value={duration}
          onChange={e => setDuration(e.target.value)} style={inp} inputMode="numeric" />
        <label style={lbl}>Calorias gastas</label>
        <input type="number" placeholder="Ex: 350" value={calories}
          onChange={e => setCalories(e.target.value)} style={inp} inputMode="numeric" />
        <label style={lbl}>Notas (opcional)</label>
        <textarea placeholder="Como correu?" value={notes}
          onChange={e => setNotes(e.target.value)} style={{ ...inp, height: 70, resize: "vertical" }} />
        <button onClick={() => { if (!duration) return;
          onSave({ id: Date.now(), workoutId, date, duration: +duration, calories: +calories || 0, notes });
        }} style={{ width: "100%", padding: 14, background: workout.color, color: "#fff",
          border: "none", borderRadius: 10, fontWeight: 800, fontSize: 15, cursor: "pointer", marginTop: 12 }}>
          Guardar sessão
        </button>
      </div>
    </div>
  );
}

// ── WEIGHT MODAL ──────────────────────────────────────────────────────────
function WeightModal({ onSave, onClose }) {
  const [weight, setWeight] = useState("");
  const [date, setDate] = useState(today());
  const inp = { width: "100%", padding: "10px 12px", background: "#0d0d1a", border: "1px solid #ffffff12",
    borderRadius: 8, color: "#f0f0f0", fontSize: 15, boxSizing: "border-box", outline: "none" };
  const lbl = { display: "block", color: "#666", fontSize: 12, fontWeight: 600,
    marginBottom: 6, marginTop: 14, textTransform: "uppercase", letterSpacing: 0.5 };
  return (
    <div style={{ position: "fixed", inset: 0, background: "#000000bb",
      display: "flex", alignItems: "flex-end", justifyContent: "center", zIndex: 100 }}>
      <div style={{ background: "#13131f", border: "1px solid #ffffff10",
        borderRadius: "20px 20px 0 0", padding: "24px 20px", width: "100%", maxWidth: 480 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
          <div style={{ fontWeight: 800, color: "#f0f0f0", fontSize: 17 }}>Registar Peso</div>
          <button onClick={onClose} style={{ background: "#ffffff0a", border: "none", color: "#888",
            width: 32, height: 32, borderRadius: 8, cursor: "pointer", fontSize: 14, fontWeight: 700 }}>✕</button>
        </div>
        <label style={lbl}>Data</label>
        <input type="date" value={date} onChange={e => setDate(e.target.value)} style={inp} />
        <label style={lbl}>Peso (kg)</label>
        <input type="number" step="0.1" placeholder="Ex: 68.5" value={weight}
          onChange={e => setWeight(e.target.value)} style={inp} inputMode="decimal" />
        <button onClick={() => { if (!weight) return; onSave({ id: Date.now(), date, weight: +weight }); }}
          style={{ width: "100%", padding: 14, background: "#f77f00", color: "#fff",
            border: "none", borderRadius: 10, fontWeight: 800, fontSize: 15, cursor: "pointer", marginTop: 12 }}>
          Guardar
        </button>
      </div>
    </div>
  );
}

// ── HISTORY TAB ───────────────────────────────────────────────────────────
function HistoryTab({ sessions, weights, onDeleteSession, onDeleteWeight }) {
  const [tab, setTab] = useState("sessions");
  const allMonths = [...new Set([
    ...sessions.map(s => monthKey(s.date)),
    ...weights.map(w => monthKey(w.date)),
  ])].sort((a, b) => b.localeCompare(a));
  const [selectedMonth, setSelectedMonth] = useState(allMonths[0] || monthKey(today()));
  const filtered = sessions.filter(s => monthKey(s.date) === selectedMonth).sort((a, b) => b.date.localeCompare(a.date));
  const filtW = weights.filter(w => monthKey(w.date) === selectedMonth).sort((a, b) => b.date.localeCompare(a.date));
  const totalDur = filtered.reduce((s, x) => s + x.duration, 0);
  const totalCal = filtered.reduce((s, x) => s + x.calories, 0);
  const delta = filtW.length >= 2 ? (filtW[0].weight - filtW[filtW.length - 1].weight).toFixed(1) : null;
  const inp = { width: "100%", padding: "10px 12px", background: "#1a1a2e", border: "1px solid #ffffff12",
    borderRadius: 8, color: "#f0f0f0", fontSize: 14, boxSizing: "border-box", outline: "none" };

  return (
    <div>
      <select value={selectedMonth} onChange={e => setSelectedMonth(e.target.value)} style={{ ...inp, marginBottom: 14 }}>
        {allMonths.map(m => <option key={m} value={m}>{getMonthName(m)}</option>)}
        {allMonths.length === 0 && <option value={monthKey(today())}>{getMonthName(monthKey(today()))}</option>}
      </select>
      <div style={{ display: "flex", gap: 8, marginBottom: 14, flexWrap: "wrap" }}>
        {[
          { label: "TREINOS", value: filtered.length, color: "#e85d04" },
          { label: "TEMPO", value: formatDuration(totalDur), color: "#2d6a4f" },
          { label: "CALORIAS", value: totalCal ? totalCal.toLocaleString("pt") + " kcal" : "—", color: "#7209b7" },
          ...(delta !== null ? [{ label: "PESO △", value: `${delta > 0 ? "+" : ""}${delta} kg`, color: delta > 0 ? "#e85d04" : "#2d6a4f" }] : []),
        ].map(s => (
          <div key={s.label} style={{ background: "#1a1a2e", border: `1px solid ${s.color}33`,
            borderRadius: 12, padding: "10px 12px", flex: 1, minWidth: 0 }}>
            <div style={{ color: "#666", fontSize: 10, fontWeight: 600 }}>{s.label}</div>
            <div style={{ color: s.color, fontWeight: 900, fontSize: 17, marginTop: 2 }}>{s.value}</div>
          </div>
        ))}
      </div>
      <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
        {["sessions", "weight"].map(t => (
          <button key={t} onClick={() => setTab(t)} style={{ flex: 1, padding: "9px 0",
            borderRadius: 8, border: "none", background: tab === t ? "#f77f00" : "#1a1a2e",
            color: tab === t ? "#fff" : "#666", fontWeight: 700, cursor: "pointer", fontSize: 13 }}>
            {t === "sessions" ? "Treinos" : "Peso"}
          </button>
        ))}
      </div>
      {tab === "sessions" && (filtered.length === 0
        ? <div style={{ color: "#444", textAlign: "center", padding: "30px 0" }}>Sem treinos registados.</div>
        : filtered.map(s => {
            const w = WORKOUTS[s.workoutId];
            return (
              <div key={s.id} style={{ background: "#1a1a2e", border: `1px solid ${w.color}22`,
                borderLeft: `3px solid ${w.color}`, borderRadius: 10, padding: "10px 14px",
                marginBottom: 8, display: "flex", gap: 10, alignItems: "center" }}>
                <div style={{ width: 36, height: 36, borderRadius: 8, background: w.color,
                  color: "#fff", display: "flex", alignItems: "center", justifyContent: "center",
                  fontWeight: 900, fontSize: 16, flexShrink: 0 }}>{s.workoutId}</div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ color: "#d0d0d0", fontWeight: 700, fontSize: 13 }}>
                    {w.label} · <span style={{ color: "#888", fontWeight: 400 }}>{s.date}</span>
                  </div>
                  <div style={{ color: "#666", fontSize: 12 }}>
                    {formatDuration(s.duration)}{s.calories ? ` · ${s.calories} kcal` : ""}{s.notes ? ` · ${s.notes}` : ""}
                  </div>
                </div>
                <button onClick={() => onDeleteSession(s.id)}
                  style={{ background: "none", border: "none", color: "#444", cursor: "pointer", fontSize: 18 }}>×</button>
              </div>
            );
          })
      )}
      {tab === "weight" && (filtW.length === 0
        ? <div style={{ color: "#444", textAlign: "center", padding: "30px 0" }}>Sem registos de peso.</div>
        : filtW.map(w => (
            <div key={w.id} style={{ background: "#1a1a2e", border: "1px solid #f77f0022",
              borderLeft: "3px solid #f77f00", borderRadius: 10, padding: "10px 14px",
              marginBottom: 8, display: "flex", alignItems: "center", gap: 10 }}>
              <div style={{ fontSize: 20 }}>⚖️</div>
              <div style={{ flex: 1 }}>
                <div style={{ color: "#d0d0d0", fontWeight: 700, fontSize: 15 }}>{w.weight} kg</div>
                <div style={{ color: "#666", fontSize: 12 }}>{w.date}</div>
              </div>
              <button onClick={() => onDeleteWeight(w.id)}
                style={{ background: "none", border: "none", color: "#444", cursor: "pointer", fontSize: 18 }}>×</button>
            </div>
          ))
      )}
    </div>
  );
}

// ── MAIN ─────────────────────────────────────────────────────────────────
export default function GymTracker() {
  const [data, setData] = useState(() => loadData());
  const [activeTab, setActiveTab] = useState("treinos");
  const [selectedWorkout, setSelectedWorkout] = useState(null);
  const [logModal, setLogModal] = useState(null);
  const [weightModal, setWeightModal] = useState(false);
  const { active: wakeLockActive, request: requestWakeLock, release: releaseWakeLock } = useWakeLock();

  useEffect(() => { saveData(data); }, [data]);

  useEffect(() => {
    if (selectedWorkout) requestWakeLock(); else releaseWakeLock();
  }, [selectedWorkout, requestWakeLock, releaseWakeLock]);

  const handleSaveSession = useCallback(s => { setData(d => ({ ...d, sessions: [...d.sessions, s] })); setLogModal(null); }, []);
  const handleSaveWeight = useCallback(e => { setData(d => ({ ...d, weights: [...d.weights, e] })); setWeightModal(false); }, []);
  const handleSaveNutrition = useCallback(n => setData(d => ({ ...d, nutrition: [...(d.nutrition||[]), n] })), []);
  const handleDeleteSession = useCallback(id => setData(d => ({ ...d, sessions: d.sessions.filter(s => s.id !== id) })), []);
  const handleDeleteWeight = useCallback(id => setData(d => ({ ...d, weights: d.weights.filter(w => w.id !== id) })), []);
  const handleDeleteNutrition = useCallback(id => setData(d => ({ ...d, nutrition: (d.nutrition||[]).filter(n => n.id !== id) })), []);

  const thisMonth = monthKey(today());
  const thisMonthS = data.sessions.filter(s => monthKey(s.date) === thisMonth);
  const totalCal = thisMonthS.reduce((s, x) => s + x.calories, 0);
  const lastW = [...data.weights].sort((a, b) => b.date.localeCompare(a.date))[0];

  const TABS = [
    { id: "treinos", icon: "💪", label: "Treinos" },
    { id: "nutricao", icon: "🥗", label: "Nutrição" },
    { id: "history", icon: "📊", label: "Histórico" },
  ];

  return (
    <div style={{ background: "#0d0d1a", minHeight: "100vh", color: "#f0f0f0",
      fontFamily: "-apple-system, sans-serif", maxWidth: 480, margin: "0 auto" }}>

      {/* Header */}
      <div style={{ background: "linear-gradient(135deg, #0d0d1a 0%, #1a0a2e 100%)",
        borderBottom: "1px solid #ffffff0a", padding: "16px 20px 12px", position: "sticky", top: 0, zIndex: 10 }}>
        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
          <div>
            <div style={{ fontWeight: 900, fontSize: 20, letterSpacing: -0.5 }}>
              <span style={{ color: "#f77f00" }}>NUNO</span><span style={{ color: "#f0f0f0" }}>FIT</span>
            </div>
            <div style={{ color: "#555", fontSize: 11 }}>
              {thisMonthS.length} treino{thisMonthS.length !== 1 ? "s" : ""} este mês
              {lastW ? ` · ${lastW.weight} kg` : ""}
              {wakeLockActive && <span style={{ color: "#2d6a4f", marginLeft: 6 }}>● ecrã ligado</span>}
            </div>
          </div>
          <button onClick={() => setWeightModal(true)} style={{ background: "#f77f0022",
            border: "1px solid #f77f0044", color: "#f77f00", borderRadius: 10,
            padding: "8px 12px", fontSize: 12, fontWeight: 700, cursor: "pointer" }}>⚖️ Peso</button>
        </div>
        {thisMonthS.length > 0 && (
          <div style={{ display: "flex", gap: 8, marginTop: 10 }}>
            <div style={{ flex: 1, background: "#e85d0411", borderRadius: 8, padding: "6px 10px", border: "1px solid #e85d0422" }}>
              <div style={{ color: "#e85d04", fontWeight: 800, fontSize: 16 }}>{thisMonthS.length}</div>
              <div style={{ color: "#555", fontSize: 10 }}>treinos</div>
            </div>
            {totalCal > 0 && (
              <div style={{ flex: 1, background: "#7209b711", borderRadius: 8, padding: "6px 10px", border: "1px solid #7209b722" }}>
                <div style={{ color: "#7209b7", fontWeight: 800, fontSize: 16 }}>{totalCal.toLocaleString("pt")}</div>
                <div style={{ color: "#555", fontSize: 10 }}>kcal treino mês</div>
              </div>
            )}
          </div>
        )}
      </div>

      {/* Body */}
      <div style={{ padding: "16px 20px", paddingBottom: 80 }}>
        {activeTab === "treinos" && (
          selectedWorkout ? (
            <WorkoutDetail id={selectedWorkout} workout={WORKOUTS[selectedWorkout]}
              onLog={id => setLogModal(id)} onBack={() => setSelectedWorkout(null)} />
          ) : (
            <div>
              <WeekSchedule onSelectWorkout={id => setSelectedWorkout(id)} />
              <div style={{ color: "#555", fontSize: 12, marginBottom: 10, textTransform: "uppercase", letterSpacing: 1 }}>
                Todos os treinos
              </div>
              <div style={{ display: "flex", flexDirection: "column", gap: 8 }}>
                {Object.entries(WORKOUTS).map(([id, w]) => (
                  <WorkoutCard key={id} id={id} workout={w} onSelect={setSelectedWorkout} />
                ))}
              </div>
            </div>
          )
        )}
        {activeTab === "nutricao" && (
          <NutritionTab
            nutrition={data.nutrition || []}
            onSave={handleSaveNutrition}
            onDelete={handleDeleteNutrition}
          />
        )}
        {activeTab === "history" && (
          <HistoryTab sessions={data.sessions} weights={data.weights}
            onDeleteSession={handleDeleteSession} onDeleteWeight={handleDeleteWeight} />
        )}
      </div>

      {/* Bottom nav */}
      <div style={{ position: "fixed", bottom: 0, left: "50%", transform: "translateX(-50%)",
        width: "100%", maxWidth: 480, background: "#0d0d1a",
        borderTop: "1px solid #ffffff0a", display: "flex", zIndex: 20 }}>
        {TABS.map(t => (
          <button key={t.id} onClick={() => { setActiveTab(t.id); setSelectedWorkout(null); }}
            style={{ flex: 1, padding: "12px 0", background: "none", border: "none",
              color: activeTab === t.id ? "#f77f00" : "#444", cursor: "pointer",
              display: "flex", flexDirection: "column", alignItems: "center", gap: 3 }}>
            <span style={{ fontSize: 20 }}>{t.icon}</span>
            <span style={{ fontSize: 10, fontWeight: 700 }}>{t.label}</span>
          </button>
        ))}
      </div>

      {logModal && <LogModal workoutId={logModal} onSave={handleSaveSession} onClose={() => setLogModal(null)} />}
      {weightModal && <WeightModal onSave={handleSaveWeight} onClose={() => setWeightModal(false)} />}
    </div>
  );
}
